            "rationale": "vapor_outlet 的 alignment_score 0.9 和 topology_score 0.89 均为最高，且 score_gap_to_next 0.14 显著高于 liquid_outlet，符合 feed_valve_flash_chain 模式中闪蒸罐顶部气相出口的典型连接需求。",
            "patch": {
              "operations": [
                {
                  "op": "add",
                  "path": "/streams/-",
                  "value": {
                    "id": "VG-502",
                    "name": "VG-502",
                    "source_unit_id": "flash-8",
                    "source_port_key": "vapor_outlet"
                  }
                }
              ]
            },
            "preview": {
              "accept_key": "Tab",
              "description": "添加名为 VG-502 的流股，连接 flash-8 的 vapor_outlet 端口。"
            },
            "apply": {
              "command_kind": "accept_ghost_completion",
